/* eslint-disable max-len */
import { Component, Host, h, Prop, Event, EventEmitter, Watch } from '@stencil/core';
import { isNullOrUndefinedOrEmptyString } from '@src/utils/mx-utils/utils';
import { IMenuItem } from '../mx-nav/mx-nav.model';
import { isVerticallyInViewport } from '@src/utils/mx-utils/domUtils';
import { IVerticalNavItem } from '../mx-vertical-nav/mx-vertical-nav.interface';

@Component({
  tag: 'mx-sub-menu',
  styleUrl: 'mx-sub-menu.css'
})
export class MxSubMenu {
  /** Sets an array of sub-menus. */
  @Prop() readonly subMenu: IMenuItem[] = [];

  @Watch('subMenu')
  onSubMenuChange() {
    this.updateItems();
  }

  /** Sets the number of the column. */
  @Prop() readonly columnNum: number;
  /** Sets the number of columns. */
  @Prop() readonly columns: number;

  /** Sets a function to handle menu clicks. */
  @Event() subMenuClickHandler: EventEmitter<IVerticalNavItem>;

  private items: IMenuItem[] = [];

  componentWillLoad() {
    this.updateItems();
  }

  // This is grouping each column of the sub-menu items based on the column number.
  private updateItems() {
    const items = [];
    for (let i = this.columnNum - 1; i < this.subMenu.length; i = i + this.columns) {
      items.push(this.subMenu[i]);
    }
    this.items = items;
  }

  private readonly onSubmenuClick = (submenu: IVerticalNavItem) => (_event) => {
    const navigateToLink: boolean = submenu.defaultBrowserNavigation && isNullOrUndefinedOrEmptyString(submenu.link);
    if (submenu.disabled || navigateToLink) {
      _event.preventDefault();
      return;
    }
    this.subMenuClickHandler.emit(submenu);
  };

  private renderSubmenuLabel(submenu: IMenuItem) {
    return submenu.label ? (
      <div class='heading-s mx-sub-menu__item-header text-tertiary'>
        { submenu.label }
        <hr class='m-0 pt-4 border-b border-t-none border-primary-inverse border-opacity-moreTransparent' />
      </div>
    ) : null;
  }

  private renderItem(submenuItem: IVerticalNavItem) {
    const verticalNavSubItem: IVerticalNavItem = submenuItem;
    let linkClass = 'mx-sub-menu__child-link px-8 py-4';
    if (verticalNavSubItem.disabled) {
      linkClass += ' text-tertiary bg-primary hover:bg-primary';
    } else if (verticalNavSubItem.selected) {
      linkClass += ' text-primary-inverse bg-brand-less-prominent hover:bg-brand-least-prominent';
    } else {
      linkClass += ' text-brand-more-prominent bg-primary hover:bg-brand-less-subtle';
    }
    const navigateToLinkImmediately: boolean = verticalNavSubItem.defaultBrowserNavigation;
    const targetAndNavigateToLink: boolean = verticalNavSubItem.target && navigateToLinkImmediately;
    const linkAndNavigateToLink: boolean = verticalNavSubItem.link && navigateToLinkImmediately;
    return (
      <li class={{
        'mx-sub-menu__item': true,
        'mx-sub-menu__item_selected': verticalNavSubItem.selected,
        'mx-sub-menu__item_disabled': verticalNavSubItem.disabled
      }}>
        <kds-link
          onMouseMove={(event) => {
            //@ts-ignore
            const infoBlock = event.currentTarget.querySelector('.mx-sub-menu__child-link-info');
            if (infoBlock != null && !isVerticallyInViewport(infoBlock)) {
              infoBlock.classList.add('mx-sub-menu__child-link-info_up');
            }
          }}
          implied={!verticalNavSubItem.selected && !verticalNavSubItem.disabled}
          target={targetAndNavigateToLink ? verticalNavSubItem.target : '_self'}
          href={linkAndNavigateToLink ? verticalNavSubItem.link : 'javascript:void(0)'}
          class='body-m'
          linkClass={linkClass}
          onClick={this.onSubmenuClick(verticalNavSubItem)}>
          { submenuItem.label }
          {
            verticalNavSubItem.disabled && verticalNavSubItem.disabledInfo != null ?
              <span>
                <kds-icon-info />
                <div class='mx-sub-menu__child-link-info text-primary-inverse bg-primary-inverse rounded-4'>
                  { verticalNavSubItem.disabledInfo }
                </div>
              </span> :
              ''
          }
        </kds-link>
      </li>
    );
  }

  render() {
    return (
      <Host>
        <ul class='list-reset'>
          {this.items?.map((submenu: IVerticalNavItem) => {
            const isItem: boolean = !isNullOrUndefinedOrEmptyString(submenu.link) || submenu.children?.length < 1;
            return (
              <li
                class={{
                  'mx-sub-menu__item-wrapper': true,
                  'mx-sub-menu__item-wrapper-no-label': isNullOrUndefinedOrEmptyString(submenu.label) || isItem
                }}>
                {
                  isItem ? this.renderItem.call(this, submenu) : this.renderSubmenuLabel(submenu)
                }
                <ul class='list-reset'>{ submenu.children?.map(this.renderItem.bind(this)) }</ul>
              </li>
            );
          })}
        </ul>
      </Host>
    );
  }
}
